" Service Definition
define service ZSD_PurchOrder
{
  expose ZI_PurchOrder as PurchaseOrder;
  expose ZI_POItem     as POItem;
}

" Service Binding - via ADT GUI
" ZSB_PO_UI  → OData V4 UI  (Fiori)
" ZSB_PO_API → OData V4 API (integration)
" Both point to ZSD_PurchOrder

" Without alias - technical name exposed
define service ZSD_BAD
{
  expose ZI_SalesOrderERPItemV2 as ZI_SalesOrderERPItemV2;
}
" OData: .../ZI_SalesOrderERPItemV2?$top=5

" With alias - clean external name
define service ZSD_GOOD
{
  expose ZI_SalesOrderERPItemV2 as SalesOrderItem;
}
" OData: .../SalesOrderItem?$top=5  ← clean

" manifest.json snippet (Fiori app descriptor)
{
  "sap.app": {
    "dataSources": {
      "mainService": {
        "uri": "/sap/opu/odata4/sap/zsalesorder
              /srvd/sap/zsd_salesorder/0001/",
        "type": "OData",
        "settings": { "odataVersion": "4.0" }
      }
    }
  },
  "sap.ui5": {
    "routing": {
      "targets": {
        "SalesOrderList": {
          "name": "sap.fe.templates.ListReport"
        }
      }
    }
  }
}

" One service definition
define service ZSD_VENDOR
{
  expose ZI_Vendor       as Vendor;
  expose ZI_VendorContact as VendorContact;
}

" Binding 1: UI (Fiori app)
" ZSB_VENDOR_UI → OData V4 - UI
" URL: /sap/opu/odata4/.../zsd_vendor/0001/

" Binding 2: API (integration)
" ZSB_VENDOR_API → OData V4 - Web API
" URL: /sap/opu/odata4/.../zsd_vendor_api/0001/
" Both expose Vendor + VendorContact

