" Managed RAP - framework handles persistence
managed implementation in class zbp_training unique;

define behavior for ZI_TrainingRecord
alias Training
persistent table ztraining_record  " ← SAP writes here
lock master
{
  create; update; delete;
  field ( readonly ) TrainingId;
  validation validateDates on save {
    field TrainingDate; }
}

" Validation only - no INSERT/UPDATE needed!
METHOD validateDates FOR VALIDATE
    IMPORTING keys FOR Training~validateDates.
  " Only check logic here
  " No DB write operations!
ENDMETHOD.

" Managed RAP - framework handles DB
managed implementation in class zbp_expense unique;
define behavior for ZI_ExpenseReport
alias Expense
persistent table zexpense_report  " ← framework writes
lock master
{
  create; update; delete;
  " No FOR MODIFY needed — framework handles it
}
" Developer only writes:
METHOD validateAmount FOR VALIDATE ...
METHOD calcTotal FOR DETERMINE ...

" Unmanaged RAP - developer handles DB
unmanaged implementation in class zbp_wrapped;
define behavior for ZI_WrappedLegacy
{
  create; update; delete;
}
METHOD modify FOR MODIFY  " ← developer writes this
    IMPORTING entities FOR CREATE Expense.
  " Call BAPI or write DB directly
  CALL FUNCTION 'BAPI_EXPENSE_CREATE' ...
ENDMETHOD.
